function searchRange(nums, target) {
  function find(first) {
    let left = 0, right = nums.length - 1;
    let ans = -1;

    while (left <= right) {
      const mid = Math.floor((left + right) / 2);

      if (nums[mid] === target) {
        ans = mid;
        if (first) right = mid - 1;
        else left = mid + 1;
      } else if (nums[mid] < target) {
        left = mid + 1;
      } else {
        right = mid - 1;
      }
    }

    return ans;
  }

  return [find(true), find(false)];
}

