function nextGreaterElement(nums1, nums2) {
  const stack = [];
  const map = new Map();

  for (const num of nums2) {
    while (stack.length && num > stack[stack.length - 1]) {
      map.set(stack.pop(), num);
    }
    stack.push(num);
  }

  while (stack.length) {
    map.set(stack.pop(), -1);
  }

  return nums1.map(n => map.get(n));
}

