List<Integer> leaders(int[] a) {
  List<Integer> res = new ArrayList<>();
  int maxRight = Integer.MIN_VALUE;
  for (int i = a.length - 1; i >= 0; i--) {
    if (a[i] >= maxRight) { res.add(a[i]); maxRight = a[i]; }
  }
  Collections.reverse(res);
  return res;
}
