// positives: sliding window
int[] subarraySum(int[] a, int target) {
  int left = 0, sum = 0;
  for (int right = 0; right < a.length; right++) {
    sum += a[right];
    while (sum > target && left <= right) sum -= a[left++];
    if (sum == target) return new int[]{left, right};
  }
  return new int[]{-1, -1};
}
