void rotate90(int[][] m) {
  int n = m.length;
  for (int i = 0; i < n; i++)                 // transpose
    for (int j = i + 1; j < n; j++) {
      int t = m[i][j]; m[i][j] = m[j][i]; m[j][i] = t;
    }
  for (int[] row : m) {                        // reverse each row
    for (int i = 0, j = n - 1; i < j; i++, j--) {
      int t = row[i]; row[i] = row[j]; row[j] = t;
    }
  }
}

